sql:
SELECT permission_name FROM permissions
WHERE permission_id IN (
    SELECT permission_id FROM user_permissions
    WHERE user_id = (SELECT user_id FROM users WHERE username = 'admin')
);

SELECT name, department 
FROM recipients 
WHERE team_id = 0;

SELECT team_id, team_name
FROM teams
WHERE manager_id IS NULL OR manager_id NOT IN (SELECT recipient_id FROM recipients);

SELECT response_count, average_response_time
FROM survey_responses_summary
WHERE survey_id = 1 AND question_id = 1 AND response_type = '1';
